454	const TIME_OF_DAY_RE = /^([01]\d|2[0-4]):([0-5]\d)$/;
455	
456	export type TriggerSpec =
457	  | { kind: 'interval'; every: string }
458	  | { kind: 'cron'; expr: string; tz: string }
459	  | { kind: 'webhook'; path: string };
460	
461	export interface ActiveHours {
462	  start: string;
463	  end: string;
464	  tz: string;
465	}
466	
467	export interface RoutineFrontmatterFields {
468	  name: string;
469	  description: string;
470	  trigger: TriggerSpec;
471	  activeHours?: ActiveHours;
472	  silenceToken?: string;
473	  silenceMaxChars: number;
474	  conversation: 'per-fire' | 'shared';
475	  promptBody: string;
476	}
477	
478	export type RoutineFrontmatterResult =
479	  | { ok: true; fields: RoutineFrontmatterFields }
480	  | { ok: false; reason: string };
481	
482	const fail = (reason: string): RoutineFrontmatterResult => ({ ok: false, reason });
483	
484	export function parseRoutineFrontmatter(text: string): RoutineFrontmatterResult {
485	  const m = FRONTMATTER_FENCE.exec(text);
486	  if (m === null) return fail('no frontmatter block');
487	  const yamlBody = m[1] ?? '';
488	  const promptBody = (m[3] ?? '').trim();
489	
490	  let parsed: unknown;
491	  try {
492	    parsed = yamlLoad(yamlBody);
493	  } catch (err) {
494	    if (err instanceof YAMLException) {
495	      return fail(`invalid YAML in frontmatter: ${err.reason}`);
496	    }
497	    return fail('invalid YAML in frontmatter');
498	  }
499	  if (parsed === null || typeof parsed !== 'object' || Array.isArray(parsed)) {
500	    return fail('frontmatter must be a YAML mapping');
501	  }
502	  const obj = parsed as Record<string, unknown>;
503	
504	  if (typeof obj['name'] !== 'string' || (obj['name'] as string).length === 0) {
505	    return fail('frontmatter missing required field: name');
506	  }
507	  if (typeof obj['description'] !== 'string' || (obj['description'] as string).length === 0) {
508	    return fail('frontmatter missing required field: description');
509	  }
510	
511	  const triggerRaw = obj['trigger'];
512	  if (triggerRaw === undefined || triggerRaw === null) {
513	    return fail('frontmatter missing required field: trigger');
514	  }
515	  if (typeof triggerRaw !== 'object' || Array.isArray(triggerRaw)) {
516	    return fail('frontmatter trigger must be a mapping');
517	  }
518	  const trigObj = triggerRaw as Record<string, unknown>;
519	  const kind = trigObj['kind'];
520	
521	  let trigger: TriggerSpec;
522	  switch (kind) {
523	    case 'interval': {
524	      const every = trigObj['every'];
525	      if (typeof every !== 'string' || every.length === 0) {
526	        return fail('interval trigger missing required field: every');
527	      }
528	      if (DURATION_RE.exec(every) === null) {
529	        return fail(`interval.every: not a valid duration (30s | 5m | 1h | 1d): ${every}`);
530	      }
531	      const seconds = durationToSeconds(every);
532	      if (seconds === null) return fail(`interval.every: cannot parse ${every}`);
533	      if (seconds < 60) {
534	        return fail(`interval.every: minimum is 60s (got ${every})`);
535	      }
536	      trigger = { kind: 'interval', every };
537	      break;
538	    }
539	    case 'cron': {
540	      const cronExpr = trigObj['expr'];
541	      const tz = trigObj['tz'];
542	      if (typeof cronExpr !== 'string' || cronExpr.length === 0) {
543	        return fail('cron trigger missing required field: expr');
544	      }
545	      if (typeof tz !== 'string' || tz.length === 0) {
546	        return fail('cron trigger requires explicit tz (no implicit local time)');
547	      }
548	      try {
549	        new Cron(cronExpr, { timezone: tz });
550	      } catch (err) {
551	        return fail(`invalid cron: ${err instanceof Error ? err.message : String(err)}`);
552	      }
553	      trigger = { kind: 'cron', expr: cronExpr, tz };
554	      break;
555	    }
556	    case 'webhook':
557	      // I3: webhook lands in Phase C.
558	      return fail('trigger.kind: webhook is not yet supported (lands in Phase C)');
559	    default:
560	      return fail(`trigger.kind: unknown value ${JSON.stringify(kind)} (expected interval | cron)`);
561	  }
562	
563	  let activeHours: ActiveHours | undefined;
564	  if (obj['activeHours'] !== undefined && obj['activeHours'] !== null) {
565	    const ah = obj['activeHours'];
566	    if (typeof ah !== 'object' || Array.isArray(ah)) {
567	      return fail('activeHours must be a mapping');
568	    }
569	    const ahObj = ah as Record<string, unknown>;
570	    const start = ahObj['start'];
571	    const end = ahObj['end'];
572	    const tz = ahObj['tz'];
573	    if (typeof start !== 'string' || !TIME_OF_DAY_RE.test(start)) {
574	      return fail(`activeHours.start: not HH:MM (got ${String(start)})`);
575	    }
576	    if (typeof end !== 'string' || !TIME_OF_DAY_RE.test(end)) {
577	      return fail(`activeHours.end: not HH:MM (got ${String(end)})`);
578	    }
579	    if (typeof tz !== 'string' || tz.length === 0) {
580	      return fail('activeHours.tz is required');
581	    }
582	    activeHours = { start, end, tz };
583	  }
584	
585	  const silenceTokenRaw = obj['silenceToken'];
586	  let silenceToken: string | undefined;
587	  if (silenceTokenRaw !== undefined && silenceTokenRaw !== null) {
588	    if (typeof silenceTokenRaw !== 'string' || silenceTokenRaw.length === 0) {
589	      return fail('silenceToken must be a non-empty string when set');
590	    }
591	    silenceToken = silenceTokenRaw;
592	  }
593	
594	  const silenceMaxRaw = obj['silenceMaxChars'];
595	  let silenceMaxChars = 300;
596	  if (silenceMaxRaw !== undefined && silenceMaxRaw !== null) {
597	    if (typeof silenceMaxRaw !== 'number' || !Number.isInteger(silenceMaxRaw) || silenceMaxRaw < 0) {
598	      return fail('silenceMaxChars must be a non-negative integer');
599	    }
600	    silenceMaxChars = silenceMaxRaw;
601	  }
602	
603	  const conversationRaw = obj['conversation'];
604	  let conversation: 'per-fire' | 'shared';
605	  if (conversationRaw === undefined || conversationRaw === null) {
606	    conversation = 'per-fire';
607	  } else if (conversationRaw === 'per-fire' || conversationRaw === 'shared') {
608	    conversation = conversationRaw;
609	  } else {
610	    return fail(`conversation: must be "per-fire" or "shared" (got ${JSON.stringify(conversationRaw)})`);
611	  }
612	
613	  const fields: RoutineFrontmatterFields = {
614	    name: obj['name'] as string,
615	    description: obj['description'] as string,
616	    trigger,
617	    silenceMaxChars,
618	    conversation,
619	    promptBody,
620	  };
621	  if (activeHours !== undefined) fields.activeHours = activeHours;
622	  if (silenceToken !== undefined) fields.silenceToken = silenceToken;
623	  return { ok: true, fields };
624	}
625	
626	export function parseRoutineFrontmatterBytes(bytes: Uint8Array): RoutineFrontmatterResult {
627	  let text: string;
628	  try {
629	    text = new TextDecoder('utf-8', { fatal: true }).decode(bytes);
630	  } catch {
631	    return fail('routine file is not valid UTF-8');
632	  }
633	  return parseRoutineFrontmatter(text);
634	}
635	
636	export function durationToSeconds(every: string): number | null {
637	  const m = DURATION_RE.exec(every);
638	  if (m === null) return null;
639	  const n = Number.parseInt(m[1]!, 10);
640	  const unit = m[2]!;
641	  switch (unit) {
642	    case 's': return n;
643	    case 'm': return n * 60;
644	    case 'h': return n * 3600;
645	    case 'd': return n * 86_400;
646	    default: return null;
647	  }
648	}
