801	import type { FileChange, Plugin, WorkspaceVersion } from '@ax/core';
802	import { reject } from '@ax/core';
803	import { parseRoutineFrontmatterBytes } from './frontmatter.js';
804	
805	const PLUGIN_NAME = '@ax/validator-routine';
806	
807	const ROUTINE_PATH = /^\.ax\/routines\/[^/]+\.md$/;
808	
809	interface PreApplyPayload {
810	  changes: FileChange[];
811	  parent: WorkspaceVersion | null;
812	  reason: string;
813	}
814	
815	export function createValidatorRoutinePlugin(): Plugin {
816	  return {
817	    manifest: {
818	      name: PLUGIN_NAME,
819	      version: '0.0.0',
820	      registers: [],
821	      calls: [],
822	      subscribes: ['workspace:pre-apply'],
823	    },
824	    init({ bus }) {
825	      bus.subscribe<PreApplyPayload>(
826	        'workspace:pre-apply',
827	        PLUGIN_NAME,
828	        async (_ctx, input) => {
829	          for (const c of input.changes) {
830	            if (c.kind !== 'put') continue;
831	            if (!ROUTINE_PATH.test(c.path)) continue;
832	            const r = parseRoutineFrontmatterBytes(c.content);
833	            if (!r.ok) {
834	              return reject({ reason: `${c.path}: ${r.reason}` });
835	            }
836	          }
837	          return undefined;
838	        },
839	      );
840	    },
841	  };
842	}
