1628	import type { ActiveHours } from '@ax/validator-routine';
1629	
1630	// We compute the tz-local hour/minute of the candidate using Intl
1631	// (zero new deps; same approach croner uses). Then compare against the
1632	// window edges. If inside, return candidate. If before start, shift to
1633	// today's start. If past end, shift to tomorrow's start.
1634	//
1635	// `end: "24:00"` means midnight at the end of the day — candidates at
1636	// or after the LOCAL midnight roll into the next-day window.
1637	
1638	interface LocalHm {
1639	  hour: number;   // 0..24 (24 represents the end sentinel only)
1640	  minute: number; // 0..59
1641	  ymd: { y: number; m: number; d: number };
1642	}
1643	
1644	function localParts(d: Date, tz: string): LocalHm {
1645	  const fmt = new Intl.DateTimeFormat('en-US', {
1646	    timeZone: tz,
1647	    year: 'numeric', month: '2-digit', day: '2-digit',
1648	    hour: '2-digit', minute: '2-digit', hour12: false,
1649	  });
1650	  const parts = Object.fromEntries(
1651	    fmt.formatToParts(d).map((p) => [p.type, p.value]),
1652	  ) as Record<string, string>;
1653	  return {
1654	    hour: parts.hour === '24' ? 0 : Number.parseInt(parts.hour, 10),
1655	    minute: Number.parseInt(parts.minute, 10),
1656	    ymd: {
1657	      y: Number.parseInt(parts.year, 10),
1658	      m: Number.parseInt(parts.month, 10),
1659	      d: Number.parseInt(parts.day, 10),
1660	    },
1661	  };
1662	}
1663	
1664	function parseHm(hm: string): { h: number; m: number } {
1665	  const [h, m] = hm.split(':');
1666	  return { h: Number.parseInt(h!, 10), m: Number.parseInt(m!, 10) };
1667	}
1668	
1669	// Build a UTC Date for "YYYY-MM-DD HH:MM" in the given tz. Uses a
1670	// fixed-point loop: pick a UTC guess, observe its rendered local time,
1671	// nudge by the difference. Two iterations suffice across all real-world
1672	// tz offsets including DST transitions.
1673	function buildLocal(ymd: { y: number; m: number; d: number }, h: number, m: number, tz: string): Date {
1674	  let guess = new Date(Date.UTC(ymd.y, ymd.m - 1, ymd.d, h, m, 0));
1675	  for (let i = 0; i < 2; i++) {
1676	    const seen = localParts(guess, tz);
1677	    const seenMs = Date.UTC(seen.ymd.y, seen.ymd.m - 1, seen.ymd.d, seen.hour, seen.minute, 0);
1678	    const wantMs = Date.UTC(ymd.y, ymd.m - 1, ymd.d, h, m, 0);
1679	    guess = new Date(guess.getTime() + (wantMs - seenMs));
1680	  }
1681	  return guess;
1682	}
1683	
1684	function addDays(ymd: { y: number; m: number; d: number }, days: number): { y: number; m: number; d: number } {
1685	  const dt = new Date(Date.UTC(ymd.y, ymd.m - 1, ymd.d));
1686	  dt.setUTCDate(dt.getUTCDate() + days);
1687	  return { y: dt.getUTCFullYear(), m: dt.getUTCMonth() + 1, d: dt.getUTCDate() };
