2698	import type { Kysely } from 'kysely';
2699	import { sql } from 'kysely';
2700	import type { RoutinesDatabase } from './migrations.js';
2701	import type { RoutinesStore } from './store.js';
2702	import type { RoutineRow, FireStatus } from './types.js';
2703	import { engineFor } from './engines/index.js';
2704	import { advanceToNextActiveWindow } from './active-hours.js';
2705	import { durationToSeconds } from '@ax/validator-routine';
2706	import type { Clock } from './clock.js';
2707	
2708	export interface FireResult {
2709	  status: FireStatus;
2710	  conversationId?: string | null;
2711	  error: string | null;
2712	}
2713	
2714	export type FireRoutineFn = (
2715	  row: RoutineRow,
2716	  source: 'tick' | 'manual',
2717	) => Promise<FireResult>;
2718	
2719	export interface TickOnceInput {
2720	  store: RoutinesStore;
2721	  fire: FireRoutineFn;
2722	  now: Date;
2723	  claimBatchSize: number;
2724	  claimWindowMinutes: number;
2725	}
2726	
2727	export async function runTickOnce(input: TickOnceInput): Promise<void> {
2728	  const claimed = await input.store.claimDue({
2729	    now: input.now,
2730	    limit: input.claimBatchSize,
2731	    claimWindowMinutes: input.claimWindowMinutes,
2732	  });
2733	
2734	  for (const row of claimed) {
2735	    // Active hours: skip + shift, no fire, no fire-row.
2736	    if (row.activeHours !== null) {
2737	      const adjusted = advanceToNextActiveWindow(input.now, row.activeHours);
2738	      if (adjusted.getTime() > input.now.getTime()) {
2739	        await input.store.advance({
2740	          agentId: row.agentId, path: row.path,
2741	          nextRunAt: adjusted,
2742	          lastRunAt: input.now,
2743	          lastStatus: row.lastStatus ?? 'ok',
2744	          lastError: row.lastError ?? null,
2745	        });
2746	        continue;
2747	      }
2748	    }
2749	
2750	    let result: FireResult;
2751	    try {
2752	      result = await input.fire(row, 'tick');
2753	    } catch (err) {
2754	      const msg = err instanceof Error ? err.message : String(err);
2755	      result = { status: 'error', error: msg, conversationId: null };
2756	    }
2757	
2758	    await input.store.recordFire({
2759	      agentId: row.agentId, path: row.path,
2760	      triggerSource: 'tick',
2761	      conversationId: result.conversationId ?? null,
2762	      status: result.status,
2763	      error: result.error,
2764	    });
2765	
2766	    const nextAt = computeNextRunAt(row, input.now);
2767	    await input.store.advance({
2768	      agentId: row.agentId, path: row.path,
2769	      nextRunAt: nextAt,
2770	      lastRunAt: input.now,
2771	      lastStatus: result.status,
2772	      lastError: result.error,
2773	    });
2774	  }
2775	}
2776	
2777	function computeNextRunAt(row: RoutineRow, now: Date): Date | null {
2778	  if (row.trigger.kind === 'webhook') return null;
2779	  const eng = engineFor(row.trigger);
2780	  if (eng === null) return null;
2781	
2782	  // Drift control. For interval, advance from previous next_run_at unless
2783	  // we're more than one interval behind — in which case jump to now+every
2784	  // to avoid a catch-up storm.
2785	  if (row.trigger.kind === 'interval') {
2786	    const seconds = durationToSeconds(row.trigger.every) ?? 0;
2787	    const prevTarget = row.nextRunAt ?? now;
2788	    const candidate = new Date(prevTarget.getTime() + seconds * 1000);
2789	    const oneIntervalAhead = new Date(now.getTime() + seconds * 1000);
2790	    const isMoreThanOneBehind =
2791	      now.getTime() - prevTarget.getTime() > seconds * 1000;
2792	    return isMoreThanOneBehind ? oneIntervalAhead : candidate;
2793	  }
2794	
2795	  return eng.nextRun(row.trigger, now);
2796	}
2797	
2798	// ---------------------------------------------------------------------------
2799	// Tick loop driver. Wraps runTickOnce in a sleep cadence + advisory-lock
2800	// election. Cancelled via AbortSignal at plugin shutdown.
2801	// ---------------------------------------------------------------------------
2802	
2803	export interface TickLoopInput {
2804	  db: Kysely<RoutinesDatabase>;
2805	  store: RoutinesStore;
2806	  fire: FireRoutineFn;
2807	  clock: Clock;
2808	  signal: AbortSignal;
2809	  tickIntervalMs: number;
2810	  electionRetryMs: number;
2811	  claimBatchSize: number;
2812	  claimWindowMinutes: number;
2813	}
2814	
2815	const ADVISORY_LOCK_KEY = 'ax/routines.tick';
2816	
2817	export async function runTickLoop(input: TickLoopInput): Promise<void> {
2818	  while (!input.signal.aborted) {
2819	    const acquired = await tryAcquireAdvisoryLock(input.db);
2820	    if (!acquired) {
2821	      await input.clock.sleep(input.electionRetryMs, input.signal);
2822	      continue;
2823	    }
2824	    try {
2825	      while (!input.signal.aborted) {
2826	        try {
2827	          await runTickOnce({
2828	            store: input.store, fire: input.fire,
2829	            now: input.clock.now(),
2830	            claimBatchSize: input.claimBatchSize,
2831	            claimWindowMinutes: input.claimWindowMinutes,
2832	          });
2833	        } catch (err) {
2834	          // I8 — tick errors must not crash the loop.
2835	          process.stderr.write(
2836	            `[ax/routines] tick error: ${err instanceof Error ? err.message : String(err)}\n`,
2837	          );
2838	        }
2839	        await input.clock.sleep(input.tickIntervalMs, input.signal);
2840	      }
2841	    } finally {
2842	      await releaseAdvisoryLock(input.db);
2843	    }
2844	  }
2845	}
2846	
2847	async function tryAcquireAdvisoryLock(db: Kysely<RoutinesDatabase>): Promise<boolean> {
2848	  const r = await sql<{ ok: boolean }>`
2849	    SELECT pg_try_advisory_lock(hashtext(${ADVISORY_LOCK_KEY})) AS ok
2850	  `.execute(db);
2851	  return r.rows[0]?.ok === true;
2852	}
2853	
2854	async function releaseAdvisoryLock(db: Kysely<RoutinesDatabase>): Promise<void> {
2855	  try {
2856	    await sql`SELECT pg_advisory_unlock(hashtext(${ADVISORY_LOCK_KEY}))`.execute(db);
2857	  } catch {
2858	    // Disconnect handles it.
2859	  }
2860	}
