3919	```ts
3920	// Rewrite jsonl bytes to exclude the named turnId (and any coalesced
3921	// continuation lines sharing its message.id). If turnId is empty, drop
3922	// the LAST user/assistant turn block. Returns the new bytes (or null
3923	// if nothing changed).
3924	export function dropTurnFromJsonl(
3925	  bytes: Uint8Array,
3926	  turnId: string,
3927	): Uint8Array | null {
3928	  const text = new TextDecoder('utf-8', { fatal: false }).decode(bytes);
3929	  if (text.length === 0) return null;
3930	  const rawLines = text.split('\n');
3931	  // Track parsed (uuid, messageId, isAssistant) for each non-blank line.
3932	  interface Parsed { line: string; uuid?: string; messageId?: string; isAssistant: boolean; isTurnBearing: boolean }
3933	  const parsed: Parsed[] = rawLines.map((line) => {
3934	    if (line.trim().length === 0) return { line, isAssistant: false, isTurnBearing: false };
3935	    try {
3936	      const o = JSON.parse(line) as { type?: string; uuid?: string; message?: { id?: string } };
3937	      const isAssistant = o.type === 'assistant';
3938	      const isTurnBearing = o.type === 'assistant' || o.type === 'user';
3939	      const result: Parsed = { line, isAssistant, isTurnBearing };
3940	      if (typeof o.uuid === 'string') result.uuid = o.uuid;
3941	      if (isAssistant && typeof o.message?.id === 'string') result.messageId = o.message.id;
3942	      return result;
3943	    } catch {
3944	      return { line, isAssistant: false, isTurnBearing: false };
3945	    }
3946	  });
