    const b = parseRoutineRow(ENC.encode('---\nname: a\ndescription: d\ntrigger:\n  kind: interval\n  every: "120s"\n---\n'));
    expect(a.ok && b.ok).toBe(true);
    if (!a.ok || !b.ok) return;
    expect(a.specHash).not.toBe(b.specHash);
  });

