// Inside init(), after the workspace:applied subscriber registration:

bus.subscribe<{
  reqId?: string;
  contentBlocks?: unknown[];
  turnId?: string;
}>('chat:turn-end', PLUGIN_NAME, async (ctx, payload) => {
  const reqId = payload.reqId ?? ctx.reqId;
