      // Subscriber MUST NOT throw — fire-and-forget.
      bus.subscribe<SessionTerminatePayload>(
        'session:terminate',
        PLUGIN_NAME,
        async (ctx, payload) => {
          await handleSessionTerminate(localStore, ctx, payload);
          return undefined;
        },
      );
    },

